/**
 * Dimensiones del bloque Tu Perfil — módulo PLANO (sin "use client") para que los
 * Server Components (catálogo /blocks, página del bloque) puedan importar estas
 * constantes sin que se evalúen a undefined → NaN en los cálculos de escala.
 *
 * Tu Perfil = Header (vault, 64) + área gris (placeholder) hasta 785 alto.
 */

export const TUPERFIL_WIDTH = 798;
// 64 (header) + 24 + [120 banner + 16 + (239 + 24 + 157 cards) + 16 + 48 logout + 16 + 100 help] + 24
export const TUPERFIL_HEIGHT = 848;

"use client";

/**
 * ProfileCard — cards del bloque «Tu Perfil».
 *
 * Card 1 «Tu Perfil» (766×239): título gradiente + fila de stats (riesgo, puntos
 *   VMC, expiración) + botón primary «Canjear Puntos VMC» (200×40) + Información
 *   Personal con 3 inputs (Nombres · Apellidos · N° documento, 228×48 c/u).
 * Card 2 «Información de Contacto» (766×157 hug): 2 columnas (Teléfono · Correo),
 *   cada una con label + «Editar» + input (355×48).
 *
 * Reutiliza los componentes Input, Button, StarIcon, InfoIcon.
 */

import type { CSSProperties, JSX, ReactNode } from "react";
import Input from "@/concorde/components/Input";
import Button from "@/concorde/components/Button";
import StarIcon from "@/concorde/components/StarIcon";
import InfoIcon from "@/concorde/components/InfoIcon";

const CARD_BASE: CSSProperties = {
  boxSizing: "border-box",
  width: 766,
  background: "#ffffff",
  borderRadius: 16,
  // Sombra centrada y sutil (como el resto de cards del proyecto), no lateral/flotante.
  boxShadow: "0 0 16px 4px rgba(0,0,0,0.08)",
  fontFamily: 'var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif)',
};

// Título con gradiente morado (VYGradientPurple: #5F3ED8 → #340091 → #140046).
const GRADIENT_TITLE: CSSProperties = {
  margin: 0,
  fontSize: 18,
  lineHeight: "24px",
  fontWeight: 800,
  backgroundImage: "linear-gradient(135deg, #5F3ED8 0%, #340091 55%, #140046 100%)",
  WebkitBackgroundClip: "text",
  backgroundClip: "text",
  color: "transparent",
  WebkitTextFillColor: "transparent",
};

// Línea separadora bajo el título (gris #E1E3E2). En Figma va de x=32 a x=766
// dentro de un card de 766 con padding 32 → sobresale 16px a cada lado del padding.
const DIVIDER: CSSProperties = { height: 1, background: "#E1E3E2", margin: "14px -16px 0" };

const LABEL: CSSProperties = { fontSize: 11, fontWeight: 700, letterSpacing: "0.04em", textTransform: "uppercase", color: "#99A1AF" };
const FIELD_LABEL: CSSProperties = { fontSize: 13, fontWeight: 500, color: "#3B1782" };
const EDITAR: CSSProperties = { fontSize: 13, fontWeight: 600, color: "#3B1782", cursor: "pointer", textDecoration: "underline", textUnderlineOffset: 2 };

interface FieldProps {
  label: string;
  width: number;
  defaultValue?: string;
  editable?: boolean;
}

function Field({ label, width, defaultValue, editable = false }: FieldProps): JSX.Element {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 8, width }}>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <span style={FIELD_LABEL}>{label}</span>
        {editable ? <span style={EDITAR}>Editar</span> : null}
      </div>
      {/* Input a ancho completo de la columna (se alarga hasta el «Editar») */}
      <Input defaultValue={defaultValue} className="pinput-fill" style={{ width: "100%" }} />
    </div>
  );
}

export interface ProfileCardProps {
  className?: string;
}

export default function ProfileCard({ className = "" }: ProfileCardProps): JSX.Element {
  return (
    <div className={className} style={{ display: "flex", flexDirection: "column", gap: 24 }}>
      {/* Los Input reutilizados traen width fija (234); .pinput-fill los alarga al ancho de su columna */}
      <style dangerouslySetInnerHTML={{ __html: ".pinput-fill.pinput-root{width:100%;}" }} />
      {/* ── Card 1: Tu Perfil (766×239) ── */}
      <section data-slot="tu-perfil-card" style={{ ...CARD_BASE, minHeight: 239, padding: "16px 32px" }}>
        <h2 style={GRADIENT_TITLE}>Tu Perfil</h2>
        <div style={DIVIDER} />

        {/* Fila de stats */}
        <div style={{ display: "flex", alignItems: "center", gap: 32, marginTop: 14 }}>
          <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
            <span style={LABEL}>Riesgo del perfil</span>
            <span style={{ fontSize: 14, fontWeight: 700, color: "#ED8936" }}>Muy bajo</span>
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
            <span style={LABEL}>Puntos VMC</span>
            <span style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 14, fontWeight: 800, color: "#3B1782", whiteSpace: "nowrap" }}>
              <StarIcon size={18} /> 500 pts <InfoIcon size={14} />
            </span>
          </div>

          <span style={{ fontSize: 13, fontWeight: 600, color: "#ED8936" }}>
            <strong>15 Puntos</strong> expirarán en 1 día
          </span>

          <div style={{ marginLeft: "auto" }}>
            <Button variant="primary" style={{ height: 40, width: 200, paddingLeft: 16, paddingRight: 16, whiteSpace: "nowrap", fontSize: 13 }}>
              Canjear Puntos VMC
            </Button>
          </div>
        </div>

        {/* Información Personal */}
        <h3 style={{ margin: "16px 0 0", fontSize: 14, fontWeight: 700, color: "#3B1782" }}>Información Personal</h3>
        <div style={{ display: "flex", justifyContent: "space-between", marginTop: 10 }}>
          <Field label="Nombres" width={228} defaultValue="Subastin" />
          <Field label="Apellidos" width={228} defaultValue="Subastin" />
          <Field label="N° documento" width={228} defaultValue="11111111" />
        </div>
      </section>

      {/* ── Card 2: Información de Contacto (766×157) ── */}
      <section data-slot="contacto-card" style={{ ...CARD_BASE, minHeight: 157, padding: "16px 32px" }}>
        <h2 style={GRADIENT_TITLE}>Información de Contacto</h2>
        <div style={DIVIDER} />
        <div style={{ display: "flex", gap: 24, marginTop: 16 }}>
          <Field label="Teléfono" width={339} defaultValue="11111111" editable />
          <Field label="Correo Electrónico" width={339} defaultValue="subastin@subastop.com" editable />
        </div>
      </section>
    </div>
  );
}

/**
 * TuPerfil — Bloque de Concorde (Voyager DS)
 *
 * Pantalla «Tu Perfil»: Header logueado + un área gris placeholder
 * (mismo gris que los banners de los demás bloques) que ocupa el resto del alto.
 *
 * Bloque = composición de componentes existentes (reusa el bloque Header).
 */

import type { CSSProperties, JSX } from "react";
import AppHeader from "@/concorde/bloques/header/desktop/Header";
import { HEADER_HEIGHT } from "@/concorde/bloques/header/desktop/dimensions";
import Button from "@/concorde/components/Button";
import ProfileCard from "./ProfileCard";
import { TUPERFIL_WIDTH, TUPERFIL_HEIGHT } from "./dimensions";

export { TUPERFIL_WIDTH, TUPERFIL_HEIGHT } from "./dimensions";

export interface TuPerfilProps {
  /** Usuario logueado — alimenta el CTA del header. */
  username?: string;
  className?: string;
}

// Banner placeholder gris (mismo estilo que Homepage / Zona / Agregar Subascoins).
const BANNER_PLACEHOLDER: CSSProperties = {
  width: 766,
  borderRadius: 8,
  background: "#E9EAEC",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  fontSize: 13,
  fontWeight: 600,
  letterSpacing: "0.06em",
  color: "#9AA1AC",
};

export default function TuPerfil({ username = "ZAEX5G", className = "" }: TuPerfilProps): JSX.Element {
  return (
    <div
      className={className}
      data-block="tu-perfil"
      style={{
        width: TUPERFIL_WIDTH,
        minHeight: TUPERFIL_HEIGHT,
        background: "#ffffff",
        display: "flex",
        flexDirection: "column",
        overflow: "hidden",
        fontFamily: 'var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif)',
      }}
    >
      <AppHeader width={TUPERFIL_WIDTH} username={username} />

      {/* Área blanca: columna de 766 (16px a cada lado = 798). No usa flex:1 para
          que abrace su contenido y el Centro de Ayuda quede pegado al botón. */}
      <div style={{ padding: "24px 16px", display: "flex", justifyContent: "center" }}>
        <div style={{ width: 766, display: "flex", flexDirection: "column", gap: 16 }}>
          {/* Banner superior 766×120 */}
          <div data-slot="banner" style={{ ...BANNER_PLACEHOLDER, height: 120 }}>
            BANNER
          </div>

          {/* Cards: Tu Perfil + Información de Contacto */}
          <ProfileCard />

          {/* Botón «Cerrar Sesión» (secondary, 200×48) centrado */}
          <div style={{ display: "flex", justifyContent: "center" }}>
            <Button variant="secondary" style={{ width: 200, paddingLeft: 24, paddingRight: 24, whiteSpace: "nowrap" }}>Cerrar Sesión</Button>
          </div>

          {/* Banner Centro de ayuda 766×100 */}
          <div data-slot="help-banner" style={{ ...BANNER_PLACEHOLDER, height: 100 }}>
            CENTRO DE AYUDA
          </div>
        </div>
      </div>
    </div>
  );
}

/**
 * Dimensiones del bloque TuPerfil · mobile — módulo plano sin "use client".
 *
 * Ancho 420 (contenido 388 con 16px de margen a cada lado). Alto aproximado:
 *   64 (header) + 16 + 120 (banner) + 16 + 524 (card Tu Perfil) + 16 + 247 (card Contacto)
 *   + 16 + 48 (Cerrar Sesión) + 16 + 116 (help) + 16
 */

export const TUPERFIL_MOBILE_WIDTH = 420;
export const TUPERFIL_MOBILE_HEIGHT = 1231;

"use client";

/**
 * ProfileCardMobile — cards del bloque «Tu Perfil» · mobile (388 ancho).
 *
 * Card 1 «Tu Perfil» (388×524): título + stats apilados (riesgo · puntos · exp.)
 *   + botón «Canjear Puntos VMC» + Información Personal con 3 inputs apilados.
 * Card 2 «Información de Contacto» (388×247): Teléfono · Correo apilados con «Editar».
 *
 * Reutiliza Input, Button, StarIcon, InfoIcon (los mismos del desktop).
 */

import type { CSSProperties, JSX } from "react";
import Input from "@/concorde/components/Input";
import Button from "@/concorde/components/Button";
import StarIcon from "@/concorde/components/StarIcon";
import InfoIcon from "@/concorde/components/InfoIcon";

const CARD_BASE: CSSProperties = {
  boxSizing: "border-box",
  width: 388,
  background: "#ffffff",
  borderRadius: 16,
  boxShadow: "0 0 16px 4px rgba(0,0,0,0.08)",
  padding: "16px 20px",
  fontFamily: 'var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif)',
};

// Título con gradiente morado (VYGradientPurple: #5F3ED8 → #340091 → #140046).
const GRADIENT_TITLE: CSSProperties = {
  margin: 0,
  fontSize: 18,
  lineHeight: "24px",
  fontWeight: 800,
  backgroundImage: "linear-gradient(135deg, #5F3ED8 0%, #340091 55%, #140046 100%)",
  WebkitBackgroundClip: "text",
  backgroundClip: "text",
  color: "transparent",
  WebkitTextFillColor: "transparent",
};

// Línea separadora bajo el título (gris #E1E3E2) — sobresale 4px del padding.
const DIVIDER: CSSProperties = { height: 1, background: "#E1E3E2", margin: "14px -16px 0" };

const LABEL: CSSProperties = { fontSize: 11, fontWeight: 700, letterSpacing: "0.04em", textTransform: "uppercase", color: "#99A1AF" };
const FIELD_LABEL: CSSProperties = { fontSize: 13, fontWeight: 500, color: "#3B1782" };
const EDITAR: CSSProperties = { fontSize: 13, fontWeight: 600, color: "#3B1782", cursor: "pointer", textDecoration: "underline", textUnderlineOffset: 2 };

interface FieldProps {
  label: string;
  defaultValue?: string;
  editable?: boolean;
}

function Field({ label, defaultValue, editable = false }: FieldProps): JSX.Element {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 8, width: "100%" }}>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <span style={FIELD_LABEL}>{label}</span>
        {editable ? <span style={EDITAR}>Editar</span> : null}
      </div>
      {/* Input a ancho completo de la card */}
      <Input defaultValue={defaultValue} className="pinput-fill" style={{ width: "100%" }} />
    </div>
  );
}

export interface ProfileCardMobileProps {
  className?: string;
}

export default function ProfileCardMobile({ className = "" }: ProfileCardMobileProps): JSX.Element {
  return (
    <div className={className} style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      {/* Los Input reutilizados traen width fija (234); .pinput-fill los alarga al ancho de la card */}
      <style dangerouslySetInnerHTML={{ __html: ".pinput-fill.pinput-root{width:100%;}" }} />

      {/* ── Card 1: Tu Perfil (388×524) ── */}
      <section data-slot="tu-perfil-card-m" style={CARD_BASE}>
        <h2 style={GRADIENT_TITLE}>Tu Perfil</h2>
        <div style={DIVIDER} />

        {/* Stats — riesgo + puntos en una fila, expiración debajo (centrados) */}
        <div style={{ display: "flex", justifyContent: "center", gap: 48, marginTop: 16, textAlign: "center" }}>
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 6 }}>
            <span style={LABEL}>Riesgo del perfil</span>
            <span style={{ fontSize: 14, fontWeight: 700, color: "#ED8936" }}>Muy bajo</span>
          </div>
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 6 }}>
            <span style={LABEL}>Puntos VMC</span>
            <span style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 14, fontWeight: 800, color: "#3B1782", whiteSpace: "nowrap" }}>
              <StarIcon size={18} /> 500 pts <InfoIcon size={14} />
            </span>
          </div>
        </div>

        <p style={{ margin: "12px 0 0", textAlign: "center", fontSize: 13, fontWeight: 600, color: "#ED8936" }}>
          <strong>15 Puntos</strong> expirarán en 1 día
        </p>

        {/* Canjear Puntos VMC — centrado */}
        <div style={{ display: "flex", justifyContent: "center", marginTop: 12 }}>
          <Button variant="primary" style={{ height: 40, width: 220, paddingLeft: 16, paddingRight: 16, whiteSpace: "nowrap", fontSize: 14 }}>
            Canjear Puntos VMC
          </Button>
        </div>

        {/* Información Personal — 3 inputs apilados */}
        <h3 style={{ margin: "16px 0 0", fontSize: 14, fontWeight: 700, color: "#3B1782" }}>Información Personal</h3>
        <div style={{ display: "flex", flexDirection: "column", gap: 12, marginTop: 12 }}>
          <Field label="Nombres" defaultValue="Subastin" />
          <Field label="Apellidos" defaultValue="Subastin" />
          <Field label="N° documento" defaultValue="11111111" />
        </div>
      </section>

      {/* ── Card 2: Información de Contacto (388×247) ── */}
      <section data-slot="contacto-card-m" style={CARD_BASE}>
        <h2 style={GRADIENT_TITLE}>Información de Contacto</h2>
        <div style={DIVIDER} />
        <div style={{ display: "flex", flexDirection: "column", gap: 12, marginTop: 16 }}>
          <Field label="Teléfono" defaultValue="11111111" editable />
          <Field label="Correo Electrónico" defaultValue="subastin@subastop.com" editable />
        </div>
      </section>
    </div>
  );
}

"use client";

/**
 * TuPerfilMobile — Bloque de Concorde (Voyager DS) · mobile (420 ancho).
 *
 *   · Header 420×64 con botón hamburguesa (abre SidebarMobile) + ícono de usuario
 *   · Banner 388×120
 *   · ProfileCardMobile (Tu Perfil 388×524 + Información de Contacto 388×247)
 *   · Botón «Cerrar Sesión» (secondary, 200×48)
 *   · Centro de Ayuda 388×116
 */

import { useState } from "react";
import type { CSSProperties, JSX } from "react";
import AppHeader from "@/concorde/bloques/header/desktop/Header";
import SidebarMobile, { SidebarMenuButton } from "@/concorde/bloques/sidebar/mobile/SidebarMobile";
import Button from "@/concorde/components/Button";
import ProfileCardMobile from "./ProfileCardMobile";
import { TUPERFIL_MOBILE_WIDTH, TUPERFIL_MOBILE_HEIGHT } from "./dimensions";

export { TUPERFIL_MOBILE_WIDTH, TUPERFIL_MOBILE_HEIGHT } from "./dimensions";

// Banner placeholder gris (mismo estilo que el desktop / demás bloques mobile).
const BANNER: CSSProperties = {
  width: 388,
  boxSizing: "border-box",
  borderRadius: 8,
  background: "#E9EAEC",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  fontSize: 12,
  fontWeight: 600,
  letterSpacing: "0.08em",
  color: "#9AA1AC",
};

export interface TuPerfilMobileProps {
  username?: string;
  className?: string;
  /** Alto del marco para previsualizaciones (px). En producción se omite. */
  frameHeight?: number;
}

export default function TuPerfilMobile({ username = "ZAEX5G", className = "", frameHeight }: TuPerfilMobileProps): JSX.Element {
  const [menuOpen, setMenuOpen] = useState(false);

  const page = (
    <div
      className={className}
      data-block="tu-perfil-mobile"
      style={{
        width: TUPERFIL_MOBILE_WIDTH,
        background: "#ffffff",
        display: "flex",
        flexDirection: "column",
        fontFamily: "var(--vmc-font-display, 'Plus Jakarta Sans', -apple-system, sans-serif)",
      }}
    >
      {/* Header 420×64 con hamburguesa + ícono de usuario (compact) */}
      <AppHeader
        width={TUPERFIL_MOBILE_WIDTH}
        username={username}
        compact
        logo={
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <SidebarMenuButton onClick={() => setMenuOpen(true)} expanded={menuOpen} />
            <img src="/logo-preview.png" alt="VMC Subastas" style={{ height: 26, width: "auto", display: "block" }} />
          </div>
        }
      />

      {/* Contenido a 16px de margen */}
      <div style={{ display: "flex", flexDirection: "column", gap: 16, padding: 16 }}>
        {/* Banner superior 388×120 */}
        <div data-slot="banner" style={{ ...BANNER, height: 120 }}>BANNER</div>

        {/* Cards: Tu Perfil + Información de Contacto */}
        <ProfileCardMobile />

        {/* Cerrar Sesión (secondary, 200×48) centrado */}
        <div style={{ display: "flex", justifyContent: "center" }}>
          <Button variant="secondary" style={{ width: 200, paddingLeft: 24, paddingRight: 24, whiteSpace: "nowrap" }}>Cerrar Sesión</Button>
        </div>

        {/* Centro de ayuda 388×116 */}
        <div data-slot="help-banner" style={{ ...BANNER, height: 116 }}>CENTRO DE AYUDA</div>
      </div>
    </div>
  );

  return (
    <SidebarMobile open={menuOpen} onOpenChange={setMenuOpen} frameHeight={frameHeight}>
      {page}
    </SidebarMobile>
  );
}

"use client";

/**
 * Input — Generado por Concorde
 * Fuente: Figma VOYAGER · "Input" (nodos 3008:15036 default · 3008:15028 focus · 3008:15044 error)
 *
 * Campo de texto 234×48, radio 16, relleno blanco. 3 variantes (por el borde):
 *   · default → borde gradiente 1px  #8460E5 → #FFF8F1
 *   · focus   → borde gradiente 2px  #ED8936 → #8460E5  + glow naranja
 *   · error   → borde rojo 1px #EF4444 + mensaje de ayuda rojo debajo
 *
 * Al enfocar (real) un input "default" toma automáticamente el borde de focus.
 */

import { forwardRef, useId } from "react";
import type { InputHTMLAttributes, JSX } from "react";

// ─── Types ────────────────────────────────────────────────────────────────────

export type InputVariant = "default" | "focus" | "error";

/**
 * Hereda los atributos nativos de <input> (type, name, id, placeholder, disabled,
 * aria-*, data-*, etc.) salvo onChange, que aquí entrega el string directo.
 * className se aplica al contenedor raíz (.pinput-root); el resto va al <input>.
 */
export interface InputProps
  extends Omit<InputHTMLAttributes<HTMLInputElement>, "onChange"> {
  /** Apariencia del borde (default "default"). El foco real activa "focus" solo. */
  variant?: InputVariant;
  /** Mensaje rojo bajo el campo — se muestra con variant="error" */
  errorMessage?: string;
  /** Recibe el string del input (no el evento). */
  onChange?: (value: string) => void;
}

// ─── Self-contained CSS ───────────────────────────────────────────────────────

const STYLE_ID = "concorde-input-styles";

const INPUT_STYLES = `
.pinput-root {
  width: 234px;
  max-width: 100%;
  font-family: var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif);
}
.pinput {
  display: flex;
  align-items: center;
  height: 48px;
  padding: 0 16px;
  border-radius: 16px;
  border: 1px solid transparent;
  /* Borde gradiente (default): #8460E5 → #FFF8F1 sobre relleno blanco */
  background-image: linear-gradient(#ffffff, #ffffff), linear-gradient(338deg, #8460E5 0%, #FFF8F1 100%);
  background-origin: border-box;
  background-clip: padding-box, border-box;
  transition: box-shadow 0.2s, border-color 0.2s;
}
.pinput__field {
  flex: 1;
  min-width: 0;
  width: 100%;
  border: none;
  outline: none;
  background: transparent;
  font-family: inherit;
  font-size: 16px;
  line-height: 20px;
  color: #191C1C;
}
.pinput__field::placeholder { color: #6B7280; }
.pinput__field:disabled { cursor: not-allowed; }

/* Focus — real (:focus-within) o forzado (variant="focus") */
.pinput:focus-within,
.pinput--focus {
  border-width: 2px;
  padding: 0 15px;
  background-image: linear-gradient(#ffffff, #ffffff), linear-gradient(148deg, #ED8936 0%, #8460E5 100%);
  box-shadow: rgba(237,137,54,0.15) 0px 2px 6px;
}

/* Error — borde rojo sólido + sin glow (gana sobre focus por orden/especificidad) */
.pinput--error,
.pinput--error:focus-within {
  border: 1px solid #EF4444;
  padding: 0 16px;
  background-image: none;
  background-color: #ffffff;
  box-shadow: none;
}
.pinput__msg {
  margin: 6px 0 0 4px;
  font-size: 13px;
  line-height: 18px;
  color: #EF4444;
}

.pinput--disabled { opacity: 0.6; }

@media (prefers-reduced-motion: reduce) {
  .pinput { transition: none; }
}
`;

let _stylesInjected = false;

// ─── Component ────────────────────────────────────────────────────────────────

const Input = forwardRef<HTMLInputElement, InputProps>(function Input({
  variant = "default",
  type = "text",
  disabled = false,
  errorMessage = "Ingresa un correo válido",
  onChange,
  className = "",
  ...rest
}, ref): JSX.Element {
  const uid = useId().replace(/:/g, "-");
  const msgId = `${uid}-msg`;
  const showMsg = variant === "error" && Boolean(errorMessage);

  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = INPUT_STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  const boxClass = [
    "pinput",
    variant === "focus" ? "pinput--focus" : "",
    variant === "error" ? "pinput--error" : "",
    disabled ? "pinput--disabled" : "",
  ].filter(Boolean).join(" ");

  return (
    <>
